<?php namespace App\Repositories\Certificate;use App\Repositories\BaseRepository;use App\Models\Certificate\CertificateTemplate;use Illuminate\Database\Eloquent\Collection;class CertificateTemplateRepository extends BaseRepository{    public function __construct(CertificateTemplate $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?CertificateTemplate    {        return $this->query()->where('name', $name)->first();    }    public function findByType(int $certificateTypeId): Collection    {        return $this->findByField('certificate_type_id', $certificateTypeId);    }    public function getActiveTemplates(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getDefaultTemplate(int $certificateTypeId): ?CertificateTemplate    {        return $this->query()->where('certificate_type_id', $certificateTypeId)->where('is_default', true)->first();    }    public function setDefault(int $id): bool    {        $template = $this->getById($id);        $this->query()->where('certificate_type_id', $template->certificate_type_id)->update(['is_default' => false]);        return $this->update($id, ['is_default' => true]);    }    public function searchTemplates(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function duplicate(int $id): CertificateTemplate    {        $source = $this->getById($id);        return $this->create([            'certificate_type_id' => $source->certificate_type_id,            'name' => $source->name . ' (Copy)',            'content' => $source->content,            'variables' => $source->variables,            'is_active' => true,            'is_default' => false,        ]);    }}